11import java .util.function .Function ;
import java .util.stream .Stream ;
public class FibonacciLambda {
public static void main (String [] args ) {
int count = 10;
// Solution 1: Avec Stream.iterate
System .out.println ("Solution 1:" );
Stream .iterate (new int[]{0, 1}, t -> new int[]{t[1], t[0] + t[1]})
.limit(count )
.map(t -> t[0])
.forEach (n -> System .out.print(n + " "));
// Solution 2: Avec fonction récursive lambda
System .out.println ("\n\nSolution 2:" );
Function <Integer , Integer > fib = n ->
(n <= 1) ? n : fib.apply (n - 1) + fib.apply (n - 2);
for (int i = 0; i < count ; i++) {
System .out.print(fib.apply (i) + " ");
}
}
}

